        import sailpoint.object.Identity;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.Operation;  
        import sailpoint.tools.Util;
        import org.apache.commons.logging.Log;
        import org.apache.commons.logging.LogFactory;	
        import sailpoint.object.ProvisioningResult;
        import sailpoint.api.Provisioner;

        Log logger = LogFactory.getLog("Ascension-Workflow-Remove-Additional-AD-Role");
        logger.debug("Ascension-Workflow-Remove-Additional-AD-Role start");

        ProvisioningPlan plan = new ProvisioningPlan();
		Identity identityObj = context.getObjectByName(Identity.class, identityName);
		if(identityObj!=null){
			plan.setIdentity(identityObj);

			plan.add("IIQ", identityName, "assignedRoles", ProvisioningPlan.Operation.Remove, roleName);

			Provisioner provisioner = new Provisioner(context);

			// if you want to remove the assignment without de-provisioning the entitlements set this

			provisioner.setNoRoleExpansion(true);

			provisioner.execute(plan);
		}
        logger.debug("Ascension-Workflow-Remove-Additional-AD-Role End");
